option.value:
param(
    [Parameter(Mandatory=$true)]
    [string]$PhpExe,

    [Parameter(Mandatory=$true)]
    [string]$DllSource
)

function Get-PHPInfo {
    param([string]$PhpExePath)
    $info = @{}
    $ver = & $PhpExePath -r "echo PHP_MAJOR_VERSION . PHP_MINOR_VERSION;" 2>$null
    $zts = & $PhpExePath -r "echo (PHP_ZTS ? 'ts' : 'nts');" 2>$null
    $arch = & $PhpExePath -r "echo (PHP_INT_SIZE == 8 ? 'x64' : 'x86');" 2>$null
    $ini = & $PhpExePath -r "echo php_ini_loaded_file();" 2>$null
    $extDir = & $PhpExePath -r "echo ini_get('extension_dir');" 2>$null
    $info.Version = $ver.Trim()
    $info.Mode = $zts.Trim()
    $info.Arch = $arch.Trim()
    $info.PhpIni = $ini.Trim()
    $info.ExtDir = $extDir.Trim()
    return $info
}

if (-not (Test-Path $PhpExe)) {
    Write-Error "php.exe introuvable à l'emplacement spécifié : $PhpExe"
    exit 1
}

if (-not (Test-Path $DllSource)) {
    Write-Error "Le dossier source des DLL n'existe pas : $DllSource"
    exit 1
}

$phpInfo = Get-PHPInfo -PhpExePath $PhpExe
Write-Host "PHP information détectée :" -ForegroundColor Cyan
Write-Host " Version (maj+min)= $($phpInfo.Version)" -ForegroundColor Yellow
Write-Host " Mode = $($phpInfo.Mode)" -ForegroundColor Yellow
Write-Host " Arch = $($phpInfo.Arch)" -ForegroundColor Yellow
Write-Host " php.ini = $($phpInfo.PhpIni)" -ForegroundColor Yellow
Write-Host " extension_dir = $($phpInfo.ExtDir)" -ForegroundColor Yellow

# Construction des noms de DLL attendus
$ver = $phpInfo.Version
$mode = $phpInfo.Mode
$arch = $phpInfo.Arch

$dllSqlsrv = "php_sqlsrv_${ver}_${mode}_${arch}.dll"
$dllPdo = "php_pdo_sqlsrv_${ver}_${mode}_${arch}.dll"

Write-Host "Recherche des fichiers : $dllSqlsrv et $dllPdo dans $DllSource" -ForegroundColor Cyan

$srcSqlsrv = Join-Path $DllSource $dllSqlsrv
$srcPdo = Join-Path $DllSource $dllPdo

if (-not (Test-Path $srcSqlsrv)) {
    Write-Warning "Fichier non trouvé: $srcSqlsrv"
}
if (-not (Test-Path $srcPdo)) {
    Write-Warning "Fichier non trouvé: $srcPdo"
}

if (-not (Test-Path $phpInfo.ExtDir)) {
    Write-Error "Le dossier extensions PHP ($($phpInfo.ExtDir)) n'existe pas. Vérifiez votre installation PHP.";
    exit 1
}

# Copie des fichiers si présents
if (Test-Path $srcSqlsrv) {
    Copy-Item -Path $srcSqlsrv -Destination $phpInfo.ExtDir -Force
    Write-Host "Copié : $srcSqlsrv -> $($phpInfo.ExtDir)"
}
if (Test-Path $srcPdo) {
    Copy-Item -Path $srcPdo -Destination $phpInfo.ExtDir -Force
    Write-Host "Copié : $srcPdo -> $($phpInfo.ExtDir)"
}

# Mise à jour du php.ini
if ($phpInfo.PhpIni -and (Test-Path $phpInfo.PhpIni)) {
    $backup = "$($phpInfo.PhpIni).bak." + (Get-Date -Format "yyyyMMddHHmmss")
    Copy-Item -Path $phpInfo.PhpIni -Destination $backup -Force
    Write-Host "Sauvegarde de php.ini : $backup"

    $iniContent = Get-Content -Path $phpInfo.PhpIni -Raw

    $lineSqlsrv = "extension=$dllSqlsrv"
    $linePdo = "extension=$dllPdo"

    if ($iniContent -notmatch [regex]::Escape($lineSqlsrv)) {
        Add-Content -Path $phpInfo.PhpIni -Value "`n$lineSqlsrv"
        Write-Host "Ajouté dans php.ini : $lineSqlsrv"
    } else {
        Write-Host "Ligne déjà présente dans php.ini : $lineSqlsrv"
    }

    if ($iniContent -notmatch [regex]::Escape($linePdo)) {
        Add-Content -Path $phpInfo.PhpIni -Value "`n$linePdo"
        Write-Host "Ajouté dans php.ini : $linePdo"
    } else {
        Write-Host "Ligne déjà présente dans php.ini : $linePdo"
    }
} else {
    Write-Warning "Impossible de localiser le fichier php.ini. Les DLL ont été copiées mais le php.ini n'a pas été modifié."
}

Write-Host "Opération terminée. Redémarrez votre serveur web / processus PHP pour prendre en compte les extensions." -ForegroundColor Green
